# Shapes module: Specific shape implementations

from geometry import Point, Shape, origin

class Rectangle(Shape):
    width: float
    height: float
    top_left: Point

    def __init__(self, top_left: Point, width: float, height: float):
        super().__init__("Rectangle")
        self.top_left = top_left
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        desc: str = super().describe()
        return f"{desc} [{self.width}x{self.height}]"

class Circle(Shape):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__("Circle")
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

def create_unit_square() -> Rectangle:
    return Rectangle(origin(), 1.0, 1.0)
